#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
int t,n;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>t;
	while(t--)
	{
		cin>>n;
		if(n==1)
		{
			cout<<"1\n";
			continue;
		}
		cout<<n-1<<" "<<n<<" ";
		for(int i=3;i<=n;i++)
		{
			if(i%2==1) cout<<n-i/2-1<<" ";
			else cout<<i/2-1<<" ";
		}
		cout<<'\n';
	}
	return 0;
}
